<?php
final class Validator { public static function email(string $e): string { if(!filter_var($e,FILTER_VALIDATE_EMAIL)) throw new InvalidArgumentException('Invalid email.'); return $e; } public static function str(string $v,int $min=1,int $max=255): string { $v=trim($v); if(mb_strlen($v)<$min||mb_strlen($v)>$max) throw new InvalidArgumentException('Invalid length.'); return $v; } public static function slug(string $v): string { $s=strtolower(trim(preg_replace('/[^a-zA-Z0-9]+/','-',$v),'-')); return $s ?: bin2hex(random_bytes(4)); } public static function money(float $v): float { if($v<=0) throw new InvalidArgumentException('Amount must be positive.'); return round($v,8); }}
